mapper.select:
SELECT r.id, r.type, hp.id AS related_id, hp.name AS related_name, hp.thumbnail AS related_thumbnail, hp.price AS related_price, u.name AS reserve_person, s.id AS reserve_staff, s.name AS reserve_staff_name, s.avatar AS reserve_staff_avatar, s.good_type AS reserve_staff_good_type, r.reserve_time, r.pay_time, r.evaluate, r.state FROM reserve r LEFT JOIN haircutting_project hp ON r.reserve_object = hp.id LEFT JOIN sys_user u ON r.create_user = u.id LEFT JOIN sys_user s ON r.reserve_staff = s.id
r.type = 1
AND r.create_user = #{reserveDTO.createUser}
AND r.reserve_staff = #{reserveDTO.reserveStaff}
AND (u.name LIKE CONCAT('%', #{reserveDTO.keyword}, '%') OR hp.name LIKE CONCAT('%', #{reserveDTO.keyword}, '%') OR s.name LIKE CONCAT('%', #{reserveDTO.keyword}, '%'))
